import React from 'react';
import './world-map.css';
import BattleMode from '../battle-mode/battle-mode'; // Import the BattleMode component

class Overworld extends React.Component {
  constructor(props) {
    super(props);

    this.state = {
      playerPosition: {
        row: 0,
        col: 0,
      },
      badGuyPosition: {
        row: 5,
        col: 5,
      },
      message: '',
      remainingMoves: 2,
      isBadGuyMoving: false,
      selectedMapIndex: 0,
      currentCountyIndex: 0,
    };

    // Local map data (replace this with your actual map data)
    this.mapsData = [
      {
        "co": "offaly",
        "emblem": "offaly",
        "county": "Co. Uíḃ Ḟailí",
        "mapData": [[3, 3, 3, 2, 2, 2, 2, 2, 9, 9],[3, 3, 30, 0, 0, 0, 0, 0, 0, 8],[3, 0, 0, 0, 0, 0, 0, 0, 31, 8],[4, 0, 0, 0, 0, 0, 0, 0, 0, 8],[4, 0, 0, 0, 0, 0, 0, 34, 0, 8],[4, 0, 32, 0, 0, 0, 0, 7, 7, 7],[4, 0, 0, 0, 0, 0, 7, 7, 7, 7],[5, 0, 0, 0, 33, 7, 7, 7, 7, 7], [5, 0, 35, 6, 6, 7, 7, 7, 7, 7],[5, 6, 6, 6, 6, 7, 7, 7, 7, 7]],
        "countyBG": "url('./countyMaps/offaly.png')",
        "top": "60px",
        "left": "16px",
        "zoom": "scale(1.7)",
        "locations": [
          "Cluain Ṁic Nóis",
          "Éadan Doire",
          "Biorra",
          "Cionn Eitigh",
          "Ráth Iomġáin",
          "Suí an Róin"
        ],
        "locationsEng": [
          "Clonmacnoise  - Meadow of the Sons of Nós ",
          "Edenderry - Hill-brow of the oak wood ",
          " Birr - plain of water ",
          "The head of Princess Eitigh ( Kinnitty )",
          "Rathangan - Iomgháin's ring-fort  ",
          "Shinrone - Seat of the seal"
        ]
      },
    ];
  }

  // Rest of your component methods...

  renderGameBoard() {
    const {
      playerPosition,
      badGuyPosition,
      selectedMapIndex,
    } = this.state;
    const selectedMap = this.mapsData[selectedMapIndex]; // Use local map data

    return selectedMap.mapData.map((row, rowIndex) => (
      <div key={`row-${rowIndex}`} className="game-row">
        {row.map((tile, colIndex) => {
          const isPlayerTile =
            rowIndex === playerPosition.row &&
            colIndex === playerPosition.col;
          const isBadGuyTile =
            badGuyPosition &&
            rowIndex === badGuyPosition.row &&
            colIndex === badGuyPosition.col;
          const rowDiff = Math.abs(
            rowIndex - playerPosition.row
          );
          const colDiff = Math.abs(
            colIndex - playerPosition.col
          );
          const isHighlighted =
            rowDiff <= this.state.remainingMoves &&
            colDiff <= this.state.remainingMoves;

          let content = null;

          if (tile === 0) {
            content = <div className="obstacle"></div>;
          } else if (
            tile >= 30 &&
            tile <= 35 &&
            isPlayerTile
          ) {
            const locationIndex = tile - 30; // Adjust to get the correct index
            content = (
              <div className="square-number">
                {selectedMap.locations[locationIndex]}
              </div>
            );
          } else {
            content = (
              <div className="square-number">{tile}</div>
            );
          }

          return (
            <div
              key={`tile-${rowIndex}-${colIndex}`}
              className={`game-tile ${
                tile === 9 ? 'non-walkable' : ''
              } ${
                isPlayerTile ? 'player-icon' : ''
              } ${
                isBadGuyTile ? 'bad-guy-icon' : ''
              } ${
                isHighlighted ? 'highlighted' : ''
              }`}
              onTouchStart={() =>
                this.handleTileTouch(rowIndex, colIndex)
              }
            >
              {content}
            </div>
          );
        })}
      </div>
    ));
  }

  render() {
    const {
      message,
      isBadGuyMoving,
      playerPosition,
      badGuyPosition,
      selectedMapIndex,
      currentCountyIndex,
    } = this.state;
    const selectedMap = this.mapsData[selectedMapIndex]; // Use local map data
    const { locations } = selectedMap;

    const currentCounty = this.mapsData[currentCountyIndex]; // Use local map data

    return (
      <div className="world-map-container">
        <h1>{message}</h1>
        <h2>{this.getLocationName(selectedMap, playerPosition)}</h2>
        <h3>Current County: {currentCounty.county}</h3> {/* Display current county name */}
        <div className="world-map">
          {this.renderGameBoard()}
          {badGuyPosition &&
            playerPosition.row === badGuyPosition.row &&
            playerPosition.col === badGuyPosition.col && (
              <BattleMode onCloseBattle={this.handleBattleClose} />
            )}
        </div>
        <button
          onClick={this.endTurn}
          disabled={isBadGuyMoving}
        >
          End Turn
        </button>
      </div>
    );
  }
}

export default Overworld;
